int pipefd[2];
if (pipe(pipefd) < 0) {
    perror("pipe");
    return -1;
}

pid_t pid = fork();
if (pid < 0) {
    perror("fork");
    close(pipefd[0]);
    close(pipefd[1]);
    return -1;
}

if (pid == 0) {
    close(pipefd[0]);
    if (dup2(pipefd[1], STDOUT_FILENO) < 0) {
        perror("dup2");
        _exit(127);
    }
    close(pipefd[1]);

    execlp("grep", "grep", q->filter, "/var/log/syslog", (char *)NULL);
    perror("execlp");
    _exit(127);
}

close(pipefd[1]);

FILE *fp = fdopen(pipefd[0], "r");
if (!fp) {
    perror("fdopen");
    close(pipefd[0]);
    (void)waitpid(pid, NULL, 0);
    return -1;
}

char line[256];
int count = 0;
while (count < q->limit && fgets(line, sizeof(line), fp)) {
    fputs(line, stdout);
    count++;
}

fclose(fp);
(void)waitpid(pid, NULL, 0);
return 0;
